  ('beginner_ppl_upper_lower_5day_lp', 'Beginner PPL + Upper/Lower', 'linear_strength', 'Five-day PPL + upper/lower beginner split with simple completion-based progression and bodybuilding accessories.', 5, 'Working-load LP + accessory double progression', 'Beginner', '2026.06.dsl', array['linear', 'beginner', 'ppl', 'upper-lower', 'hypertrophy', '5-day']::text[]),
