  ('power_hypertrophy_ppl_5day', 'Power + Hypertrophy PPL', 'wave_powerbuilding', 'Five-day powerbuilding split: power upper/lower followed by hypertrophy push, pull, and legs sessions.', 5, 'Power LP + hypertrophy double progression', 'Intermediate', '2026.06.dsl', array['powerbuilding', 'volume', 'hypertrophy', 'ppl', '5-day']::text[]),
  ('training_max_wave_pump_5day', 'Training Max Wave + Pump', 'training_max_wave', 'Five-day training-max wave: the four main-lift days plus a low-stress pump/supplemental day.', 5, 'Training-max wave + pump day', 'Intermediate', '2026.06.dsl', array['training max', 'wave', 'strength', 'hypertrophy', '5-day']::text[]),
  ('classic_bodypart_split_5day_lp', 'Classic Bodypart Split', 'linear_strength', 'Five-day classic bodypart split with one regulated main lift per major day and double-progressed accessories.', 5, 'Hypertrophy working-load LP', 'Beginner', '2026.06.dsl', array['bodybuilding', 'hypertrophy', 'bro split', 'linear', '5-day']::text[])
